export interface TJGAsset {
  id: string;
  name: string;
  category: TJGCategory;
  subcategory: string;
  modelPath: string;
  thumbnailHint: string;
  polyLevel: "low" | "medium" | "high";
  hasAnimations: boolean;
  animationCount: number;
  hasSkeleton: boolean;
  boneCount: number;
  vertexCount: number;
  tags: string[];
  usableInGame: boolean;
  needsRetexture: boolean;
  sceneCompatible: string[];
  description: string;
}

export type TJGCategory =
  | "character"
  | "animal"
  | "building"
  | "weapon"
  | "item"
  | "vehicle"
  | "nature"
  | "ship";

export interface TJGTexture {
  id: string;
  name: string;
  path: string;
  category: string;
  tags: string[];
}

export interface TJGScene {
  id: string;
  name: string;
  description: string;
  genre: string;
  assets: string[];
  concepts: string[];
  thumbnail?: string;
}

export interface TJGSound {
  id: string;
  name: string;
  path: string;
  tags: string[];
}

