export const ALL_TJG_ASSETS: TJGAsset[] = [
  ...TJG_CHARACTERS,
  ...TJG_ANIMALS,
  ...TJG_BUILDINGS,
  ...TJG_WEAPONS,
  ...TJG_NATURE,
  ...TJG_VEHICLES,
];

export function getTJGAssetById(id: string): TJGAsset | undefined {
  return ALL_TJG_ASSETS.find(a => a.id === id);
}

export function getTJGAssetsByCategory(category: TJGCategory): TJGAsset[] {
  return ALL_TJG_ASSETS.filter(a => a.category === category);
}

export function getTJGGameplayAssets(): TJGAsset[] {
  return ALL_TJG_ASSETS.filter(a => a.usableInGame);
}

export function getTJGRetextureNeeded(): TJGAsset[] {
  return ALL_TJG_ASSETS.filter(a => a.needsRetexture);
}

export function getTJGFantasyCharacters(): TJGAsset[] {
  return TJG_CHARACTERS.filter(a => a.subcategory === "fantasy" && a.usableInGame);
}

export function searchTJGAssets(query: string): TJGAsset[] {
  const q = query.toLowerCase();
  return ALL_TJG_ASSETS.filter(a =>
    a.name.toLowerCase().includes(q) ||
    a.description.toLowerCase().includes(q) ||
    a.tags.some(t => t.includes(q))
  );
}
